/*
======================================================================
Design System & Global Styles
======================================================================
*/

:root {
    /* Color palette */
    --color-primary-deep: #A21B1B;   /* deep ministry red */
    --color-primary-gold: #F2C84B;   /* cross / accent gold */

    --color-secondary-warm: #F5A25A; /* warm orange highlight */
    --color-secondary-plum: #6B4C7D; /* dusk purple */

    --color-neutral-black: #000000;
    --color-neutral-white: #FFFFFF;
    --color-neutral-cream: #F2E4D5;

    --color-success: #3B7A57;
    --color-error: #A21B1B;
    --color-warning: #E2B13C;
    --color-info: #325A8C;

    /* Derived neutrals */
    --color-text-on-hero: #111111;
    --color-text-muted: #5B4736;
    --color-border-soft: #D6C5B4;

    /* Typography */
    --font-heading: 'Cinzel', Georgia, serif;
    --font-body: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif;
    --font-mono: 'Source Code Pro', SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;

    --font-size-h1: clamp(3.4rem, 4.6vw, 4.2rem); /* ~56-64px */
    --font-size-h2: clamp(2.2rem, 3vw, 2.5rem);    /* ~36-40px */
    --font-size-h3: clamp(1.75rem, 2.4vw, 2rem);   /* ~28-32px */
    --font-size-body: 1.125rem;                    /* 18px base body */
    --font-size-small: 0.875rem;                   /* 14px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing scale (8px base) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;
    --space-7: 96px;

    /* Layout */
    --site-max-width: 1120px;
}

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-black);
    background-color: var(--color-neutral-cream);
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: var(--color-primary-deep);
    text-decoration: none;
}

a:hover,
a:focus-visible {
    color: #7F1414;
}

a:focus-visible,
button:focus-visible,
[tabindex='-1']:focus-visible {
    outline: 2px solid var(--color-primary-gold);
    outline-offset: 2px;
}

/*
======================================================================
Hero Shell & Background
======================================================================
*/

.hero-shell {
    min-height: 100vh;
    position: relative;
}

.hero-shell::before {
    /* Full-page photographic background with warm sunset tones */
    content: '';
    position: fixed;
    inset: 0;
    z-index: -2;
    background-image:
        linear-gradient(
            to bottom,
            rgba(242, 228, 213, 0.95) 0%,
            rgba(245, 162, 90, 0.85) 35%,
            rgba(107, 76, 125, 0.9) 80%,
            rgba(0, 0, 0, 0.95) 100%
        ),
        url('images/hero-background.jpg'); /* Replace with actual sunset-prayer image path */
    background-size: cover;
    background-position: center bottom;
    background-repeat: no-repeat;
}

.hero-shell::after {
    /* Subtle radial glow at the bottom center to echo sunburst */
    content: '';
    position: fixed;
    left: 50%;
    bottom: 0;
    transform: translateX(-50%);
    width: 120%;
    height: 60%;
    z-index: -1;
    background: radial-gradient(
        circle at 50% 100%,
        rgba(242, 200, 75, 0.7) 0%,
        rgba(242, 200, 75, 0.0) 55%
    );
    pointer-events: none;
}

/*
======================================================================
Header & Navigation
======================================================================
*/

.site-header {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    padding: var(--space-2) var(--space-4);
    z-index: 10;
    text-align: center;
}

.site-nav {
    display: flex;
    justify-content: center;
}

.nav-list {
    list-style: none;
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-3);
    margin: 0;
    padding: 0;
}

.nav-item a {
    font-family: var(--font-heading);
    font-size: 0.95rem;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--color-primary-deep);
    transition: color 150ms ease-out, text-shadow 150ms ease-out;
}

.nav-item a:hover,
.nav-item a:focus-visible {
    color: #7F1414;
    text-shadow: 0 0 1px rgba(0, 0, 0, 0.2);
}

/*
======================================================================
Hero Title & Content Area
======================================================================
*/

.hero {
    min-height: 100vh;
    display: flex;
    align-items: stretch;
    justify-content: center;
    padding: var(--space-7) var(--space-2) var(--space-6);
}

.hero-inner {
    width: 100%;
    max-width: var(--site-max-width);
    margin: 0 auto;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.hero-title-block {
    text-align: center;
    margin-bottom: var(--space-5);
}

.hero-cross {
    display: inline-block;
    font-size: 2.4rem;
    line-height: 1;
    color: var(--color-primary-gold);
    text-shadow:
        0 0 6px rgba(242, 200, 75, 0.8),
        0 0 18px rgba(242, 200, 75, 0.7);
    margin-bottom: var(--space-1);
}

.hero-title {
    margin: 0;
    font-family: var(--font-heading);
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: var(--color-primary-deep);
}

.site-main {
    /* Central page content area that overlays the hero image */
    width: 100%;
    max-width: 800px;
    margin: 0 auto;
    padding: var(--space-4) var(--space-3) var(--space-6);
    border-radius: 4px;
    text-align: center;
    color: var(--color-text-on-hero);
}

.site-main > *:first-child {
    margin-top: 0;
}

.site-main p {
    margin-top: 0;
    margin-bottom: var(--space-2);
    line-height: var(--line-height-relaxed);
}

.site-main h2,
.site-main h3 {
    font-family: var(--font-heading);
    margin-top: var(--space-3);
    margin-bottom: var(--space-2);
}

.site-main h2 {
    font-size: var(--font-size-h2);
}

.site-main h3 {
    font-size: var(--font-size-h3);
}

/*
======================================================================
Footer
======================================================================
*/

.site-footer {
    background: rgba(242, 228, 213, 0.97);
    border-top: 1px solid var(--color-border-soft);
    padding: var(--space-4) var(--space-3) var(--space-3);
    color: var(--color-text-muted);
}

.footer-inner {
    max-width: var(--site-max-width);
    margin: 0 auto;
}

.footer-nav {
    margin-bottom: var(--space-3);
}

.footer-links {
    list-style: none;
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--space-1) var(--space-3);
    padding: 0;
    margin: 0;
}

.footer-item a {
    font-family: var(--font-heading);
    font-size: 0.8rem;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: var(--color-primary-deep);
    white-space: nowrap;
}

.footer-item a:hover,
.footer-item a:focus-visible {
    color: #7F1414;
}

.footer-meta {
    text-align: center;
    font-size: var(--font-size-small);
}

.footer-ministry-name {
    margin: 0 0 var(--space-0-5);
    font-family: var(--font-heading);
    letter-spacing: 0.16em;
    text-transform: uppercase;
}

.footer-copy {
    margin: 0;
}

/*
======================================================================
Responsive Adjustments
======================================================================
*/

@media (max-width: 768px) {
    .site-header {
        padding-inline: var(--space-2);
    }

    .nav-list {
        gap: var(--space-1);
    }

    .nav-item a {
        font-size: 0.8rem;
        letter-spacing: 0.1em;
    }

    .hero {
        padding-top: var(--space-6);
        padding-inline: var(--space-2);
    }

    .hero-title-block {
        margin-bottom: var(--space-4);
    }

    .site-main {
        padding-inline: var(--space-2);
    }
}

@media (max-width: 480px) {
    .hero-title {
        letter-spacing: 0.12em;
    }

    .footer-links {
        justify-content: flex-start;
    }
}
